import { Logger } from '@nestjs/common';
import { performance } from 'perf_hooks';

import { LogExecution, maskSensitiveData } from '@decorators/log-execution.decorator';

describe('maskSensitiveData', () => {
	describe('primitives and nullish values', () => {
		it('should return null unchanged', () => {
			expect(maskSensitiveData(null)).toBeNull();
		});

		it('should return undefined unchanged', () => {
			expect(maskSensitiveData(undefined)).toBeUndefined();
		});

		it('should return a string unchanged', () => {
			expect(maskSensitiveData('hello')).toBe('hello');
		});

		it('should return a number unchanged', () => {
			expect(maskSensitiveData(42)).toBe(42);
		});

		it('should return a boolean unchanged', () => {
			expect(maskSensitiveData(false)).toBe(false);
		});
	});

	describe('flat objects', () => {
		it('should mask default sensitive key: password', () => {
			const result = maskSensitiveData({ password: 'secret123', name: 'Alice' }) as Record<string, unknown>;
			expect(result['password']).toBe('***MASKED***');
			expect(result['name']).toBe('Alice');
		});

		it('should mask default sensitive key: token', () => {
			const result = maskSensitiveData({ token: 'abc123' }) as Record<string, unknown>;
			expect(result['token']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: secret', () => {
			const result = maskSensitiveData({ secret: 'shhh' }) as Record<string, unknown>;
			expect(result['secret']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: auth', () => {
			const result = maskSensitiveData({ auth: 'bearer abc' }) as Record<string, unknown>;
			expect(result['auth']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: authorization', () => {
			const result = maskSensitiveData({ authorization: 'Bearer xyz' }) as Record<string, unknown>;
			expect(result['authorization']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: cookie', () => {
			const result = maskSensitiveData({ cookie: 'session=abc' }) as Record<string, unknown>;
			expect(result['cookie']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: apiKey', () => {
			const result = maskSensitiveData({ apiKey: 'key-123' }) as Record<string, unknown>;
			expect(result['apiKey']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: refreshToken', () => {
			const result = maskSensitiveData({ refreshToken: 'rt-abc' }) as Record<string, unknown>;
			expect(result['refreshToken']).toBe('***MASKED***');
		});

		it('should mask default sensitive key: accessToken', () => {
			const result = maskSensitiveData({ accessToken: 'at-abc' }) as Record<string, unknown>;
			expect(result['accessToken']).toBe('***MASKED***');
		});

		it('should mask case-insensitively when key contains sensitive substring', () => {
			const result = maskSensitiveData({ UserPassword: 'hunter2', PublicKey: 'ok' }) as Record<string, unknown>;
