describe('LogExecution', () => {
	let logSpy: jest.SpyInstance;
	let warnSpy: jest.SpyInstance;
	let errorSpy: jest.SpyInstance;

	beforeEach(() => {
		logSpy = jest.spyOn(Logger.prototype, 'log').mockImplementation(jest.fn());
		warnSpy = jest.spyOn(Logger.prototype, 'warn').mockImplementation(jest.fn());
		errorSpy = jest.spyOn(Logger.prototype, 'error').mockImplementation(jest.fn());
	});

	afterEach(() => jest.clearAllMocks());

	describe('default options', () => {
		it('should log params and response, mask sensitive data, and return result', async () => {
			class TestService {
				@LogExecution()
				async doWork(input: { password: string; name: string }): Promise<{ token: string; id: number }> {
					return { token: 'secret-token', id: 1 };
				}
			}

			const svc = new TestService();
			const result = await svc.doWork({ password: 'abc', name: 'Alice' });

			expect(result).toEqual({ token: 'secret-token', id: 1 });
			expect(logSpy).toHaveBeenCalledTimes(2);

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('Invoked');
			expect(invokedCall).toContain('***MASKED***');
			expect(invokedCall).not.toContain('abc');

			const completedCall = logSpy.mock.calls[1][0] as string;
			expect(completedCall).toContain('Completed in');
			expect(completedCall).toContain('***MASKED***');
			expect(completedCall).not.toContain('secret-token');
		});
	});

	describe('logParams: false', () => {
		it('should skip the Invoked log entry', async () => {
			class TestService {
				@LogExecution({ logParams: false })
				async doWork(): Promise<string> {
					return 'result';
				}
			}

			const svc = new TestService();
			await svc.doWork();

			const messages = logSpy.mock.calls.map((c) => c[0] as string);
			expect(messages.every((m) => !m.includes('Invoked'))).toBe(true);
			expect(messages.some((m) => m.includes('Completed in'))).toBe(true);
		});
	});

	describe('logResponse: false', () => {
		it('should omit response field from the completion log', async () => {
			class TestService {
				@LogExecution({ logResponse: false })
				async doWork(): Promise<{ name: string }> {
					return { name: 'Alice' };
				}
			}

			const svc = new TestService();
			await svc.doWork();

			const completedCall = logSpy.mock.calls.find((c) =>
				(c[0] as string).includes('Completed in'),
			);
			expect(completedCall).toBeDefined();
			const msg = completedCall![0] as string;
			expect(msg).not.toContain('"response"');
		});
	});

	describe('logExecutionTime: false', () => {
		it('should skip the Completed log entry entirely', async () => {
			class TestService {
				@LogExecution({ logExecutionTime: false })
				async doWork(): Promise<string> {
					return 'done';
				}
			}

			const svc = new TestService();
			await svc.doWork();

			const messages = logSpy.mock.calls.map((c) => c[0] as string);
			expect(messages.every((m) => !m.includes('Completed in'))).toBe(true);
		});
	});

	describe('maskSensitiveData: false', () => {
		it('should log raw params and response without masking', async () => {
			class TestService {
				@LogExecution({ maskSensitiveData: false })
				async doWork(data: { password: string }): Promise<{ token: string }> {
					return { token: 'raw-token' };
				}
			}

			const svc = new TestService();
			await svc.doWork({ password: 'plain' });

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('plain');

			const completedCall = logSpy.mock.calls[1][0] as string;
			expect(completedCall).toContain('raw-token');
		});
	});

	describe('paramFormatter', () => {
		it('should use paramFormatter output instead of raw args', async () => {
			class TestService {
				@LogExecution({ paramFormatter: () => ({ formatted: true }) })
				async doWork(input: string): Promise<string> {
					return 'ok';
				}
			}

			const svc = new TestService();
			await svc.doWork('raw-value');

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('"formatted":true');
			expect(invokedCall).not.toContain('raw-value');
		});
	});

	describe('responseFormatter', () => {
		it('should use responseFormatter output instead of raw response', async () => {
			class TestService {
				@LogExecution({ responseFormatter: () => ({ formatted: true }) })
				async doWork(): Promise<{ data: string }> {
					return { data: 'real-data' };
				}
			}

			const svc = new TestService();
			await svc.doWork();

			const completedCall = logSpy.mock.calls.find((c) =>
				(c[0] as string).includes('Completed in'),
			);
			expect(completedCall).toBeDefined();
			const msg = completedCall![0] as string;
			expect(msg).toContain('"formatted":true');
			expect(msg).not.toContain('real-data');
		});
	});

	describe('customContext', () => {
		it('should include custom context fields in all log entries', async () => {
			class TestService {
				@LogExecution({ customContext: { requestId: 'req-abc', tenant: 'acme' } })
				async doWork(): Promise<string> {
					return 'done';
				}
			}

			const svc = new TestService();
			await svc.doWork();

			for (const call of logSpy.mock.calls) {
				const msg = call[0] as string;
				expect(msg).toContain('req-abc');
				expect(msg).toContain('acme');
			}
		});
	});

	describe('sensitiveKeys', () => {
		it('should use custom sensitiveKeys to mask specific fields', async () => {
			class TestService {
				@LogExecution({ sensitiveKeys: ['mySecret'], maskSensitiveData: true })
				async doWork(data: { mySecret: string; safe: string }): Promise<{ mySecret: string; safe: string }> {
					return { mySecret: 'hide-this', safe: 'keep-this' };
				}
			}

			const svc = new TestService();
			await svc.doWork({ mySecret: 'input-secret', safe: 'visible' });

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('***MASKED***');
			expect(invokedCall).toContain('visible');

			const completedCall = logSpy.mock.calls[1][0] as string;
			expect(completedCall).toContain('***MASKED***');
			expect(completedCall).toContain('keep-this');
		});
	});

	describe('slow execution warning', () => {
		it('should emit a warn log when execution exceeds 3000ms', async () => {
			let callCount = 0;
			const performanceSpy = jest.spyOn(performance, 'now').mockImplementation(() => {
				callCount++;
				return callCount === 1 ? 0 : 4000;
			});

			class TestService {
				@LogExecution()
				async doWork(): Promise<string> {
					return 'slow';
				}
			}

			const svc = new TestService();
			await svc.doWork();

			expect(warnSpy).toHaveBeenCalledTimes(1);
			const warnMsg = warnSpy.mock.calls[0][0] as string;
			expect(warnMsg).toContain('Slow execution');
			expect(warnMsg).toContain('TestService.doWork');

			performanceSpy.mockRestore();
		});

		it('should not emit a warn log when execution is under 3000ms', async () => {
			class TestService {
				@LogExecution()
				async doWork(): Promise<string> {
					return 'fast';
				}
			}

			const svc = new TestService();
			await svc.doWork();

			expect(warnSpy).not.toHaveBeenCalled();
		});
	});

	describe('error handling', () => {
		it('should log error message and stack, then re-throw', async () => {
			const boom = new Error('something exploded');

			class TestService {
				@LogExecution()
				async doWork(): Promise<never> {
					throw boom;
				}
			}

			const svc = new TestService();
			await expect(svc.doWork()).rejects.toThrow('something exploded');

			expect(errorSpy).toHaveBeenCalledTimes(1);
			const [msg, stack] = errorSpy.mock.calls[0] as [string, string];
			expect(msg).toContain('Failed after');
			expect(msg).toContain('something exploded');
			expect(stack).toBe(boom.stack);
		});
	});

	describe('request object detection', () => {
		it('should extract {method, url, ip, userAgent} when arg looks like a Fastify request', async () => {
			const fakeRequest = {
				raw: {},
				socket: {},
				headers: { 'user-agent': 'Mozilla/5.0' },
				hostname: 'localhost',
				ip: '127.0.0.1',
				protocol: 'https',
				routeOptions: {},
				routerPath: '/test',
				method: 'GET',
				url: '/test?q=1',
			};

			class TestService {
				@LogExecution({ maskSensitiveData: false })
				async doWork(req: typeof fakeRequest): Promise<string> {
					return 'ok';
				}
			}

			const svc = new TestService();
			await svc.doWork(fakeRequest);

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('"method":"GET"');
			expect(invokedCall).toContain('"url":"/test?q=1"');
			expect(invokedCall).toContain('"ip":"127.0.0.1"');
			expect(invokedCall).toContain('"userAgent":"Mozilla/5.0"');
			expect(invokedCall).not.toContain('"routerPath"');
		});

		it('should not treat an object without enough keys as a request', async () => {
			const notARequest = { raw: {}, socket: {} };

			class TestService {
				@LogExecution({ maskSensitiveData: false })
				async doWork(obj: typeof notARequest): Promise<string> {
					return 'ok';
				}
			}

			const svc = new TestService();
			await svc.doWork(notARequest);

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).not.toContain('"method"');
			expect(invokedCall).toContain('"raw"');
		});
	});

	describe('response object detection', () => {
		it('should replace arg with "[FastifyReply]" when it has send and status functions', async () => {
			const fakeReply = {
				send: jest.fn(),
				status: jest.fn(),
			};

			class TestService {
				@LogExecution({ maskSensitiveData: false })
				async doWork(reply: typeof fakeReply): Promise<string> {
					return 'ok';
				}
			}

			const svc = new TestService();
			await svc.doWork(fakeReply);

			const invokedCall = logSpy.mock.calls[0][0] as string;
			expect(invokedCall).toContain('[FastifyReply]');
		});
	});

	describe('className and methodName in log context', () => {
		it('should include className and methodName from the decorated class and method', async () => {
			class MySpecialService {
				@LogExecution()
				async processItem(): Promise<string> {
					return 'done';
				}
			}

			const svc = new MySpecialService();
			await svc.processItem();

			for (const call of logSpy.mock.calls) {
				const msg = call[0] as string;
				expect(msg).toContain('MySpecialService');
				expect(msg).toContain('processItem');
			}
		});
	});
});

