		const invokedCall = logSpy.mock.calls[0][0] as string;
		expect(invokedCall).not.toContain('[FastifyReply]');
		expect(invokedCall).toContain('null');
	});

	it('should not treat a primitive string arg as a response or request object', async () => {
		class TestService {
			@LogExecution({ maskSensitiveData: false })
			async doWork(_val: string): Promise<string> {
				return 'ok';
			}
		}

		const svc = new TestService();
